170→/// Single-quote a string for POSIX shell.
171→///
172→/// Wraps in single quotes, escaping embedded single quotes via the
173→/// standard `'\''` pattern (end quote, escaped quote, begin quote).
174→fn zjjrlg_shell_quote(s: &str) -> String {
175→    format!("'{}'", s.replace('\'', "'\\''"))
176→}
