182→/// Resolve officium ID to its directory path.
183→fn zjjrlg_officium_dir(officium_id: &str) -> PathBuf {
184→    let bare_id = officium_id.trim_start_matches(OFFICIUM_SUN_PREFIX);
185→    PathBuf::from(OFFICIA_DIR).join(bare_id)
186→}
187→
188→/// Resolve legatio token to its state file path within an officium.
189→fn zjjrlg_legatio_path(officium_dir: &Path, token: &str) -> PathBuf {
190→    officium_dir.join(format!("{}{}{}", LEGATIO_FILE_PREFIX, token, LEGATIO_FILE_EXT))
191→}
192→
193→/// Mint a new legatio token by scanning existing files in the officium.
194→///
195→/// Token format: `L0`, `L1`, `L2`, ... (incrementing within officium).
196→fn zjjrlg_mint_token(officium_dir: &Path) -> String {
197→    let mut max_num: i32 = -1;
198→    if let Ok(entries) = std::fs::read_dir(officium_dir) {
199→        for entry in entries.flatten() {
200→            let name = entry.file_name();
201→            let name = name.to_string_lossy();
202→            if let Some(rest) = name.strip_prefix(LEGATIO_FILE_PREFIX) {
203→                if let Some(num_str) = rest.strip_suffix(LEGATIO_FILE_EXT) {
204→                    // Token is "L0", "L1", etc. — strip the L prefix for parsing.
205→                    if let Some(digits) = num_str.strip_prefix('L') {
206→                        if let Ok(num) = digits.parse::<i32>() {
207→                            if num > max_num { max_num = num; }
208→                        }
209→                    }
210→                }
211→            }
212→        }
213→    }
214→    format!("L{}", max_num + 1)
215→}
