439→/// Reap stale officium directories by heartbeat mtime.
440→/// Returns (reaped_count, active_count) for summary reporting.
441→fn zjjrm_exsanguinate(officia: &Path) -> (usize, usize) {
442→    let entries = match std::fs::read_dir(officia) {
443→        Ok(e) => e,
444→        Err(_) => return (0, 0),
445→    };
446→    let now = std::time::SystemTime::now();
447→    let mut reaped: usize = 0;
448→    let mut active: usize = 0;
449→    for entry in entries.flatten() {
450→        let path = entry.path();
451→        if !path.is_dir() { continue; }
452→        let dir_name = match path.file_name() {
453→            Some(n) => n.to_string_lossy().to_string(),
454→            None => continue,
455→        };
456→        if dir_name.starts_with('.') { continue; }
457→        let heartbeat = path.join(HEARTBEAT_FILE);
458→        if !heartbeat.exists() {
459→            // No heartbeat file — legacy or corrupt. Log warning, skip.
460→            eprintln!("jjx exsanguinate: no heartbeat in {:?}, skipping", path.file_name());
461→            continue;
462→        }
463→        let mtime = match heartbeat.metadata().and_then(|m| m.modified()) {
464→            Ok(t) => t,
465→            Err(_) => continue,
466→        };
467→        let age = match now.duration_since(mtime) {
468→            Ok(d) => d,
469→            Err(_) => continue,
470→        };
471→        if age.as_secs() > EXSANGUINATION_THRESHOLD_SECS {
472→            if let Err(e) = std::fs::remove_dir_all(&path) {
473→                eprintln!("jjx exsanguinate: failed to remove {:?}: {}", path.file_name(), e);
474→            } else {
475→                reaped += 1;
476→            }
477→        } else {
478→            active += 1;
479→        }
480→    }
481→    (reaped, active)
482→}
