676→/// Verify curia git state is clean and pushed before remote dispatch.
677→/// Returns Ok(()) if ready, Err(message) if not.
678→fn zjjrlg_require_curia_ready() -> Result<(), String> {
679→    // Check working tree is clean
680→    let status = vvc::vvce_git_command(&["status", "--porcelain"])
681→        .output()
682→        .map_err(|e| format!("git status failed: {}", e))?;
683→    let status_text = String::from_utf8_lossy(&status.stdout);
684→    let dirty_count = status_text.lines().filter(|l| !l.is_empty()).count();
685→    if dirty_count > 0 {
686→        return Err(format!(
687→            "curia working tree is dirty ({} files). Commit before dispatching.", dirty_count
688→        ));
689→    }
690→
691→    // Check HEAD is pushed to origin
692→    let head = vvc::vvce_git_command(&["rev-parse", "HEAD"])
693→        .output()
694→        .map_err(|e| format!("git rev-parse HEAD failed: {}", e))?;
695→    let head_sha = String::from_utf8_lossy(&head.stdout).trim().to_string();
696→
697→    let branch = vvc::vvce_git_command(&["rev-parse", "--abbrev-ref", "HEAD"])
698→        .output()
699→        .map_err(|e| format!("git rev-parse --abbrev-ref failed: {}", e))?;
700→    let branch_name = String::from_utf8_lossy(&branch.stdout).trim().to_string();
701→
702→    let remote_ref = format!("origin/{}", branch_name);
703→    let remote = vvc::vvce_git_command(&["rev-parse", &remote_ref])
704→        .output()
705→        .map_err(|e| format!("git rev-parse {} failed: {}", remote_ref, e))?;
706→    let remote_sha = String::from_utf8_lossy(&remote.stdout).trim().to_string();
707→
708→    if head_sha != remote_sha {
709→        return Err(format!(
710→            "curia HEAD {} is not pushed to {} (remote {}). Push before dispatching.",
711→            &head_sha[..8.min(head_sha.len())],
712→            remote_ref,
713→            &remote_sha[..8.min(remote_sha.len())]
714→        ));
715→    }
716→
717→    Ok(())
718→}
